mapper.select:
select *
from VW_SHW_HGFX v
WHERE 1=1


    and zygsdm =#{hgfxSearchReqVo.zygsdm}


    and zhwchm like'%'||#{hgfxSearchReqVo.zhwchm}||'%'


    and HWMCH_XL like'%'||#{hgfxSearchReqVo.hwmchXl}||'%'


    and bgdh =#{hgfxSearchReqVo.bgdh}


    and DGRQ>= to_date(#{hgfxSearchReqVo.startTm},'yyyy-mm-dd hh24:mi:ss')


    and DGRQ <= to_date(#{hgfxSearchReqVo.endTm},'yyyy-mm-dd hh24:mi:ss')


    and xh>=#{hgfxSearchReqVo.xh}


    and xh <=#{hgfxSearchReqVo.xh2}


  AND lb=#{hgfxSearchReqVo.lb}

order by id desc,ywchm desc,fxrq desc

select rownum,a.* ,tdh||'/'||imo||'/'||dlhc||'/'||ywchm||'/'||fxrq as fxdvalue from ( select trim(XCD_ID) xcdId,substr(trim(TRANSPORT_ID),3)imo, trim(VOYAGE_NO) dlhc,trim(BILL_NO) tdh,TRANSPORT_NAME ywchm, TO_CHAR(to_date(AUDIT_DATE,'YYYY-MM-DD"T"HH24:MI:SS'),'yyyy-mm-dd hh24:mi:ss') fxrq from RZGWL.BT_EDI_XCD_MESSAGE where 1=1
and substr(trim(TRANSPORT_ID),3)=#{imo}
and trim(VOYAGE_NO) =#{dlhc}
and trim(BILL_NO) like #{tdh}||'%'
order by fxrq desc ) a where rownum <= 100
